/**
 * Hello Command Extension
 *
 * Demonstrates a basic custom slash command for pi.
 *
 * Usage:
 * 1. This file is located at ~/.pi/agent/extensions/hello-command.ts
 * 2. Run `/reload` to load the extension
 * 3. Use `/hello` to see the greeting
 * 4. Use `/hello your name` for a personalized greeting
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

export default function helloCommandExtension(pi: ExtensionAPI) {
	// Register a simple slash command: /hello
	pi.registerCommand("hello", {
		description: "Greet the user with a friendly message",
		handler: async (args, ctx) => {
			const name = args.trim() || "friend";
			const greeting = `Hello, ${name}! 👋`;

			// Display notification in the UI
			ctx.ui.notify(greeting, "info");
		},
	});

	// Optional: Register another command with arguments
	pi.registerCommand("weather", {
		description: "Show weather info (demo: replace with real API call)",
		getArgumentCompletions: (prefix) => {
			const cities = ["London", "New York", "Tokyo", "Paris", "Sydney"];
			const filtered = cities
				.filter((c) => c.toLowerCase().startsWith(prefix.toLowerCase()))
				.map((c) => ({ value: c, label: c }));
			return filtered.length > 0 ? filtered : null;
		},
		handler: async (args, ctx) => {
			const city = args.trim() || "your location";
			ctx.ui.notify(`☀️ Weather for ${city}: Sunny, 72°F (demo)`, "info");
		},
	});
}

