/**
 * Review Command Extension
 *
 * Registers a /review command that spawns a sub-agent to perform code reviews.
 * The sub-agent analyzes code for bugs, security issues, and error handling gaps.
 *
 * Usage:
 *   /review <file-or-directory>          # Review a specific file or directory
 *   /review --model claude-sonnet-4 file  # Use specific model
 *   /review --provider anthropic file     # Use specific provider
 *
 * Note: This spawns a new pi process via bash, so it has a fresh context window
 * and won't interfere with the current conversation.
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

const REVIEW_PROMPT = `You are a code reviewer. Your task is to analyze the provided code for:

1. **Bugs and Logic Errors**: Look for off-by-one errors, race conditions, infinite loops, null dereferences, incorrect operator usage, unreachable code, etc.

2. **Security Issues**: Identify injection vulnerabilities (SQL, command, XSS), authentication/authorization flaws, insecure data handling, hardcoded secrets, improper input validation, etc.

3. **Error Handling Gaps**: Look for missing try-catch blocks, unhandled promise rejections, missing null checks, silent failures, improper resource cleanup, etc.

Instructions:
- Read the file(s) specified by the user using the read tool.
- Thoroughly analyze the code structure, logic, and patterns.
- Report each issue found with:
  - The file path and line number
  - A description of the issue
  - The severity (critical / high / medium / low)
  - A suggested fix if applicable

If no issues are found, clearly state it. Be thorough but concise.`;

export default function reviewExtension(pi: ExtensionAPI) {
	pi.registerCommand("review", {
		description: "Spawn a sub-agent to review code for bugs, security issues, and error handling gaps",
		handler: async (args, ctx) => {
			const argParts = args.trim().split(/\s+/);

			// Parse optional flags
			let model: string | undefined;
			let provider: string | undefined;
			const paths: string[] = [];

			for (let i = 0; i < argParts.length; i++) {
				const part = argParts[i];
				if (part === "--model" && i + 1 < argParts.length) {
					model = argParts[++i];
				} else if (part === "--provider" && i + 1 < argParts.length) {
					provider = argParts[++i];
				} else if (!part.startsWith("--")) {
					paths.push(part);
				}
			}

			// Build the target specification
			const target = paths.join(" ") || ".";

			// Show notification that review is starting
			ctx.ui.notify(`🔍 Starting code review for: ${target}`, "info");

			// Build pi command arguments
			const piArgs = ["--print", "--no-session"];

			if (provider) {
				piArgs.push("--provider", provider);
			}

			if (model) {
				piArgs.push("--model", model);
			}

			// The prompt to the sub-agent
			const fullPrompt = `${REVIEW_PROMPT}\n\nPlease review: ${target}`;

			// Spawn pi process
			const startTime = Date.now();
			let reviewOutput = "";
			let hadError = false;

			try {
				const result = await pi.exec("pi", [...piArgs, fullPrompt], {
					cwd: ctx.cwd,
					timeout: 120000, // 2 minute timeout
				});

				reviewOutput = result.stdout || "";

				if (result.stderr) {
					reviewOutput += "\n\n[stderr]: " + result.stderr;
				}

				if (result.code !== 0 && result.code !== null) {
					hadError = true;
					reviewOutput = `⚠️ Sub-agent exited with code ${result.code}\n\n${reviewOutput}`;
				}
			} catch (error) {
				hadError = true;
				reviewOutput = `❌ Error running review: ${error instanceof Error ? error.message : String(error)}`;
			}

			const duration = ((Date.now() - startTime) / 1000).toFixed(1);

			// Truncate if too long for display
			const maxDisplayLength = 3000;
			let displayOutput = reviewOutput;
			let wasTruncated = false;
			if (reviewOutput.length > maxDisplayLength) {
				displayOutput = reviewOutput.slice(0, maxDisplayLength) + "\n\n... (truncated)";
				wasTruncated = true;
			}

			// Report findings
			const header = hadError 
				? `⚠️ Code review completed with issues (${duration}s)`
				: `✅ Code review completed (${duration}s)`;

			const fullReport = `${header}\n\nReview target: ${target}${model ? ` (model: ${model})` : ""}${provider ? ` (provider: ${provider})` : ""}\n\n${"=".repeat(50)}\n\n${displayOutput}`;

			// Output the report to the user
			ctx.ui.notify(fullReport, hadError ? "warning" : "success");

			// Also log to console for full output if truncated
			if (wasTruncated || reviewOutput.length > 500) {
				console.log("\n" + "=".repeat(60));
				console.log("CODE REVIEW REPORT");
				console.log("=".repeat(60));
				console.log(reviewOutput);
				console.log("=".repeat(60) + "\n");
			}
		},
	});
}
